mapper.select:
SELECT id, username, password, email, nickname, auth_type, social_id, created_at, updated_at
FROM users
WHERE id = #{id, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}

SELECT id, username, password, email, nickname, auth_type, social_id, created_at, updated_at
FROM users
WHERE username = #{username}

SELECT id, username, password, email, nickname, auth_type, social_id, created_at, updated_at
FROM users
WHERE email = #{email}

SELECT id, username, password, email, nickname, auth_type, social_id, created_at, updated_at
FROM users
WHERE auth_type = #{authType} AND social_id = #{socialId}
